import{_ as i,o as l,c as t,ae as a}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Manage Fraud Rules","description":"","frontmatter":{"title":"Manage Fraud Rules","slug":"fraud-rules"},"headers":[],"relativePath":"marketer-hub/fraud-rules.md","filePath":"marketer-hub/fraud-rules.md"}'),r={name:"marketer-hub/fraud-rules.md"};function o(s,e,n,u,c,d){return l(),t("div",null,[...e[0]||(e[0]=[a('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch recommends creating fraud rules to block erroneous attribution credit in real-time. While Branch still performs last-click attribution, it will not send the ad network a postback when the attribution is flagged as fraudulent.</p><p>This has two benefits:</p><ul><li>You can see how many fraudulent events come from each ad partner and sub-publisher.</li><li>You do not have to try to recoup losses from the ad network, because the payout never happened in the first place.</li></ul><p>Blocked events are also separated from normal traffic in your Branch dashboard, so you can see all events in one place (the fraud dashboard), while healthy analytics are not distorted by bad traffic.</p><p>But not to worry, blocked events are still deep linked, so blocking would not affect the user experience of a real user.</p><div class="tip custom-block"><p class="custom-block-title">In-Depth Fraud &amp; Recommendations</p><p>Because Fraud Detection is very complex, visit our guide on understanding fraud and recommendations <a href="./in-depth-fraud-recommendations.html">here</a>.</p></div><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to enable Fraud Rules, you need to have completed the following:</p><ol><li><p>Created a <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p>Enabled Ads for your Branch account.</p><ul><li>Contact your Branch account manager or visit <a href="https://branch.io/pricing" target="_blank" rel="noreferrer">https://branch.io/pricing</a></li></ul></li><li><p>Implemented the Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>)</p><ul><li><a href="./track-branch-events.html">Track events</a></li></ul></li><li><p>Have sufficient <a href="./add-manage-users-roles-permissions-access.html">access/permissions</a> rights for your Branch app.</p><ul><li>Creating, enabling, or disabling requires <strong>Edit</strong> access to the <strong>Fraud Settings &amp; Data</strong> permission.</li><li>Viewing rules require <strong>View</strong> access to to the <strong>Fraud Settings &amp; Data</strong> permission.</li></ul></li></ol><h2 id="universal-rules" tabindex="-1">Universal Rules <a class="header-anchor" href="#universal-rules" aria-label="Permalink to &quot;Universal Rules&quot;">​</a></h2><p>Universal rules block events that violate Branch&#39;s universal fraud criteria and are enabled for all Branch accounts.</p><div class="info custom-block"><p class="custom-block-title">Universal Rules Permanently Enabled</p><p>Since Branch&#39;s Universal Rules cover the most basic and necessary protection against fraud, you cannot disable these rules.</p></div><h3 id="suspicious-ip" tabindex="-1">Suspicious IP <a class="header-anchor" href="#suspicious-ip" aria-label="Permalink to &quot;Suspicious IP&quot;">​</a></h3><p>Branch automatically blocks events coming from TOR networks and obviously suspicious IPs.</p><p><strong>Fraud Name - IP</strong></p><h3 id="suspicious-persona" tabindex="-1">Suspicious Persona <a class="header-anchor" href="#suspicious-persona" aria-label="Permalink to &quot;Suspicious Persona&quot;">​</a></h3><p>This is based on Branch’s cross-platform link graph. We use proprietary algorithms to dynamically block attributions on browsers and devices showing suspicious behavior.</p><p><strong>Fraud Name - PERSONA_FRAUD</strong></p><h2 id="standard-rules" tabindex="-1">Standard Rules <a class="header-anchor" href="#standard-rules" aria-label="Permalink to &quot;Standard Rules&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Recommendation</p><p>While Standard Rules aren&#39;t enabled by default, Branch recommend enabling the following:</p><ul><li>Click Injection</li><li>Conversion Time</li></ul></div><p>Standard rules block events based on the most common fraud patterns. These are available to all Branch customers but are not activated by default. We highly encourage all customers to enable Standard Fraud Rules as soon as possible.</p><p>Standard rules can generally be used to block the following events, though specific rules might be more restrictive:</p><ul><li>All Events</li><li>Clicks</li><li>Installs</li><li>Opens</li><li>Web Session Starts</li><li>Reinstalls</li><li>Commerce Event</li><li>Custom Event</li></ul><p>Standard Fraud Rules can also be filtered so that they only apply to a specific subset of your traffic. For example, you might want to set up separate Conversion Time rules for iOS and Android, a Geo Conflict rule that applies only to specific campaigns, or a Device Conflict rule that only applies to certain especially-risky countries. All of this (and much more) is possible with filters.</p><p>The following filters are generally available, though again specific rules might be more restrictive. If they are, this is specifically called out in the individual rule&#39;s section below.</p><ul><li>Ad Name</li><li>Ad Partner</li><li>Ad Partner (3p)</li><li>Ad ID</li><li>Ad Set ID</li><li>Ad Set Name</li><li>Agency ID</li><li>Agency Name</li><li>Brand</li><li>Campaign</li><li>Campaign ID</li><li>Channel</li><li>Creative Name</li><li>Country</li><li>Customer Ad Name</li><li>Customer Ad Set Name</li><li>Customer Campaign</li><li>Customer Event Alias</li><li>Customer Keyword</li><li>Customer Placement</li><li>Customer Secondary Publisher</li><li>Customer Sub Site Name</li><li>Device Type</li><li>Environment</li><li>Feature</li><li>First Event For User</li><li>Geo Country Name</li><li>Geo DMA Code</li><li>Keyword</li><li>Last Attributed Touch ID</li><li>Last Attributed Touch Type</li><li>Model</li><li>Name</li><li>Operating System</li><li>Placement</li><li>Platform</li><li>Reengagement Activity Attributed</li><li>Region</li><li>Secondary Publisher</li><li>Stage</li><li>Sub Site Name</li><li>Tags</li><li>Custom</li></ul><h3 id="click-injection" tabindex="-1">Click Injection <a class="header-anchor" href="#click-injection" aria-label="Permalink to &quot;Click Injection&quot;">​</a></h3><p>When a malicious app or SDK on a user&#39;s Android device tries to insert a fake ad click between when a legitimate app is downloaded and when it is first opened (thus taking unearned credit for that install).</p><p><strong>Fraud Name:</strong> CLICK_INJECTION<br><strong>Events:</strong> The Click Injection rule can <strong>only</strong> be used to block INSTALL events.<br><strong>Filters:</strong> All filters are available for the Click Injection rule.<br><strong>Notes:</strong> The Click Injection rule only works for Android devices because it relies on the secondsFromLastAttributedTouchToStoreInstallBegin field (which is only available for installs via Google Play).</p><p>Based on Branch&#39;s internal studies, we recommend setting the range for blocking to -126 to -6 seconds (the defaults for this rule). Every app is different, however, and the optimal values for your app may be different from these. When in doubt the defaults are a good starting point - but discuss with your team or your Branch CSM to be extra sure.</p><h3 id="geo-conflict" tabindex="-1">Geo Conflict <a class="header-anchor" href="#geo-conflict" aria-label="Permalink to &quot;Geo Conflict&quot;">​</a></h3><p>The click and the install occur in different countries, as inferred from their respective IP addresses. This can occasionally happen with real users, but much more often indicates that the click or install was simulated.</p><p><strong>Fraud Name:</strong> GEO_CONFLICT<br><strong>Events:</strong> The Geo Conflict rule can block any event.<br><strong>Filters:</strong> Only the following filters are available for the Geo Conflict rule:</p><ul><li>Country: Country as inferred from OS preference.</li><li>Geo Country Code: Country as inferred from IP address.</li></ul><p><strong>Notes:</strong> If you do business in a region of the world where there are many countries close together there is more risk of false positives from this rule. For example, a user on the border of France and Germany might legitimately click in one country and convert in the other, especially if you use Geo Country Code (which is based on IP). If this applies to your business, consider adding additional filters or disabling this rule entirely. Start by analyzing your traffic - if you work with a Branch CSM, consider discussing this with them.</p><h3 id="conversion-time" tabindex="-1">Conversion Time <a class="header-anchor" href="#conversion-time" aria-label="Permalink to &quot;Conversion Time&quot;">​</a></h3><p>Very short click-to-install times are suspicious - this is typically caused by faked clicks taking attribution credit for real installs. We recommend blocking CTI times below 30 seconds, but you can configure it to be up to 60 seconds. On the Branch Fraud Dashboard, you can see CTI time distribution by ad partner to determine if this threshold seems to be working.</p><p><strong>Fraud Name:</strong> CONVERSION_TIME<br><strong>Events:</strong> The Conversion Time rule can block any event.<br><strong>Filters:</strong> All filters are available for the Conversion Time rule.</p><h3 id="device-conflict" tabindex="-1">Device Conflict <a class="header-anchor" href="#device-conflict" aria-label="Permalink to &quot;Device Conflict&quot;">​</a></h3><p>The device information on the click and the install are different. A real user clicks and installs on the same device, so this is highly suspicious.</p><p><strong>Fraud Name:</strong> DEVICE_CONFLICT<br><strong>Events:</strong> The Device Conflict rule can block any event.<br><strong>Filters:</strong> Only the following filters are available for the Device Conflict rule:</p><ul><li>Brand</li><li>Model</li><li>OS</li></ul><h2 id="custom-rules" tabindex="-1">Custom Rules <a class="header-anchor" href="#custom-rules" aria-label="Permalink to &quot;Custom Rules&quot;">​</a></h2><p>Custom rules block events based on any attribute(s) that Branch stores at the event level.</p><p>Custom rules can be used to block the following events:</p><ul><li>All Events</li><li>Clicks</li><li>Installs</li><li>Opens</li><li>Web Session Starts</li><li>Reinstalls</li><li>Commerce Event</li><li>Custom Event</li></ul><h3 id="event-level-characteristics" tabindex="-1">Event-level Characteristics <a class="header-anchor" href="#event-level-characteristics" aria-label="Permalink to &quot;Event-level Characteristics&quot;">​</a></h3><p>We can block on any attribute stored at the event level.</p><p><strong>Fraud Name:</strong> CUSTOM</p><p>Example:</p><ul><li><strong>Device Pattern:</strong> For example, “OS + Country + Model”. It’s common for device farms to use the same devices over and over, making it easy to pick out specific device characteristics to block.</li></ul><div class="info custom-block"><p class="custom-block-title">Fraud Rules Consisting only of NOT clauses</p><p>If your fraud rule consists <strong>only</strong> of NOT clauses (like NOT userData.geoCountryCode:&quot;US&quot; AND NOT userData.os:&quot;ANDROID&quot;) please add at least one positive constraint, such as &quot;AND Name Exists&quot; as well.</p></div><p>The following filters are available:</p><ul><li>Ad Name</li><li>Ad Partner</li><li>Ad Partner (3p)</li><li>Ad ID</li><li>Ad Set ID</li><li>Ad Set Name</li><li>Agency ID</li><li>Agency Name</li><li>Brand</li><li>Campaign</li><li>Campaign ID</li><li>Channel</li><li>Creative Name</li><li>Country</li><li>Customer Ad Name</li><li>Customer Ad Set Name</li><li>Customer Campaign</li><li>Customer Event Alias</li><li>Customer Keyword</li><li>Customer Placement</li><li>Customer Secondary Publisher</li><li>Customer Sub Site Name</li><li>Device Type</li><li>Environment</li><li>Feature</li><li>First Event For User</li><li>Geo Country Name</li><li>Geo DMA Code</li><li>Keyword</li><li>Last Attributed Touch ID</li><li>Last Attributed Touch Type</li><li>Model</li><li>Name</li><li>Operating System</li><li>Placement</li><li>Platform</li><li>Reengagement Activity Attributed</li><li>Region</li><li>Secondary Publisher</li><li>Stage</li><li>Sub Site Name</li><li>Tags</li><li>Custom</li></ul><h2 id="once-ever-rules" tabindex="-1">Once Ever Rules <a class="header-anchor" href="#once-ever-rules" aria-label="Permalink to &quot;Once Ever Rules&quot;">​</a></h2><p>Once Ever Rules cap events that should only occur once per user.</p><p>For example, perhaps it should only be possible for a given user to register once, but fraudsters are sending many fake registration events per user in the hopes of getting paid out for those conversions. A Once Ever Rule on the Registration event will prevent this.</p><p>Once Ever rules can be used to block the following events:</p><ul><li>Installs</li><li>Opens</li><li>Purchases</li><li>Complete Registrations</li></ul><p><strong>Fraud Name:</strong> ONCE<em>EVER_CAPPED</em>_</p><h2 id="threshold-rules" tabindex="-1">Threshold Rules <a class="header-anchor" href="#threshold-rules" aria-label="Permalink to &quot;Threshold Rules&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Recommendation</p><p>Branch recommends enabling the following thresholds:</p><ul><li>Low Conversion Rate (CTI) Android</li><li>Low Conversion Rate (CTI) iOS</li></ul></div><p>Threshold Rules block events for a group when it violates a threshold.</p><p>Threshold rules can be used to block the following events:</p><ul><li>All Events</li><li>Clicks</li><li>Installs</li><li>Opens</li><li>Web Session Starts</li><li>Reinstalls</li><li>Commerce Event</li><li>Custom Event</li></ul><div class="tip custom-block"><p class="custom-block-title">Threshold Logic</p><p>Threshold rules require the following inputs:</p><ul><li><p>Minimum number of events you want to allow before rule is applied.</p><ul><li>Example: &quot;Only apply the threshold rule to sub-publishers driving at least 30 installs.&quot; This ensures that results are more statistically-significant.</li></ul></li><li><p>Ratio of fraudulent indications to overall number of events before the rule is applied.</p><ul><li>Example: &quot;Block sub-publishers with a conversion rate from click to install of less than 0.1%.&quot;</li></ul></li></ul><p>The threshold must be met across a 24hr period for it to be applied.</p><p>Once the threshold has been met, the rule will be applied to all subsequent events by that sub-publisher for the following <strong>14 days</strong>.</p></div><h3 id="low-conversion-rate-cti-android" tabindex="-1">Low Conversion Rate (CTI) Android <a class="header-anchor" href="#low-conversion-rate-cti-android" aria-label="Permalink to &quot;Low Conversion Rate (CTI) Android&quot;">​</a></h3><p>The ratio of clicks to installs by sub publisher is suspiciously low for Android.</p><h3 id="low-conversion-rate-cti-ios" tabindex="-1">Low Conversion Rate (CTI) iOS <a class="header-anchor" href="#low-conversion-rate-cti-ios" aria-label="Permalink to &quot;Low Conversion Rate (CTI) iOS&quot;">​</a></h3><p>The ratio of clicks to installs by sub publisher is suspiciously low for iOS.</p><h3 id="young-persona-rate-high" tabindex="-1">Young Persona Rate High <a class="header-anchor" href="#young-persona-rate-high" aria-label="Permalink to &quot;Young Persona Rate High&quot;">​</a></h3><p>The ratio of installs coming from young personas to the total installs by sub-publisher is high. This is an indicator that an unusually high percentage of the Installs that sub-publisher is driving are devices Branch has never seen before.</p><div class="info custom-block"><p class="custom-block-title">Adding New Threshold Rules</p><p>New types of threshold rules will be added over time. If you need a specific threshold rule for your business, please contact <a href="./submit-a-ticket.html">Support</a> to request a new type of threshold rule to be built.</p></div><h2 id="helpful-tips" tabindex="-1">Helpful Tips <a class="header-anchor" href="#helpful-tips" aria-label="Permalink to &quot;Helpful Tips&quot;">​</a></h2><h4 id="exempting-partners" tabindex="-1">Exempting Partners <a class="header-anchor" href="#exempting-partners" aria-label="Permalink to &quot;Exempting Partners&quot;">​</a></h4><p>If you want to exempt a partner (ex. Facebook or Google Adwords) from a Standard or Custom fraud rule, you can add a filter for Ad Partner (3p), change the &quot;equals&quot; to &quot;does not equal&quot; and then add the partner&#39;s 3P value (ex. <code>a_google_adwords</code>, <code>a_facebook</code>) in the final box then click <strong>Save</strong>.</p><p>You can find the Ad Partner&#39;s 3p value in the partner settings of the <a href="https://dashboard.branch.io/ads/partner-management" target="_blank" rel="noreferrer">Partner Management page</a>.</p><p>Once a partner is exempted from the rule, they will not be flagged for that rule moving forward from when you made the change. Fraud rules are not retroactive so historical data will not be updated.</p>',79)])])}const m=i(r,[["render",o]]);export{p as __pageData,m as default};
